package com.harmony.retail.web;

import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.core.Authentication;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.bind.annotation.ControllerAdvice;
import org.springframework.web.bind.annotation.ModelAttribute;

/**
 * 全 Controller 共通の Model 属性を提供する Advice。
 *
 * - storeName / copyright / version: application.properties (UTF-8 source @Value default)
 * - userName: Spring Security の SecurityContext から取得 (techStack.auth.method=session)
 *
 * Generated by Harmony /generate-code (RFC #1021 pl-7) — Gadget の ModelAttribute 配線。
 */
@ControllerAdvice
public class CommonModelAdvice {

    @Value("${app.session.storeName:店舗未選択}")
    private String storeName;

    @Value("${app.copyright:© 2026 Harmony Retail Inc.}")
    private String copyright;

    @Value("${app.version:v1.0.0}")
    private String version;

    @ModelAttribute("storeName")
    public String storeName() {
        return storeName;
    }

    /**
     * 現在ログイン中のユーザー名を返す。
     * 未認証 (SecurityContext に Authentication が無い or anonymousUser) の場合は "ゲスト"。
     * Spring Security の form login 成功時は username (e.g. "demo") が入る。
     */
    @ModelAttribute("userName")
    public String userName() {
        Authentication auth = SecurityContextHolder.getContext().getAuthentication();
        if (auth == null || !auth.isAuthenticated() || "anonymousUser".equals(auth.getName())) {
            return "ゲスト";
        }
        return auth.getName();
    }

    @ModelAttribute("copyright")
    public String copyright() {
        return copyright;
    }

    @ModelAttribute("version")
    public String version() {
        return version;
    }
}
